    def _is_rate_limited(self, addr):
        """Check if an IP address has exceeded the rate limit."""
        ip = addr[0]
        now = time.time()
        
        # Clean old entries
        self.request_counts[ip] = [
            t for t in self.request_counts[ip]
            if now - t < self.RATE_LIMIT_WINDOW
        ]
        
        if len(self.request_counts[ip]) >= self.RATE_LIMIT_MAX_REQUESTS:
            return True
        
        self.request_counts[ip].append(now)
        return False
    
    def _generate_challenge(self, addr):
        """Generate a challenge token for the client to prove non-spoofed IP."""
        ip = addr[0]
